// src/pages/Home.js

import React from "react";
import HeroSlider from "../components/HeroSlider";
import PopularProducts from "../components/Popularproducts";


const Home = () => {
  return (
    <div>
      {/* Replace old Hero with HeroSlider */}
      <HeroSlider />
      
      {/* Popular products below slider */}
      <PopularProducts />
    </div>
  );
};

export default Home;
